import fs from "node:fs";
import path from "node:path";
import Database from "better-sqlite3";

export interface Post {
  id: number;
  title: string;
  body: string;
}

export interface PageResult {
  posts: Post[];
  hasMore: boolean;
}

export const PAGE_SIZE = 10;
export const TOTAL_POSTS = 47;

let dbInstance: Database.Database | null = null;

function getDb(): Database.Database {
  if (dbInstance) {
    return dbInstance;
  }

  const dataDir = path.join(process.cwd(), ".data");
  if (!fs.existsSync(dataDir)) {
    fs.mkdirSync(dataDir, { recursive: true });
  }
  const dbPath = path.join(dataDir, "feed.sqlite3");

  const db = new Database(dbPath);
  db.pragma("journal_mode = WAL");

  db.exec(`
    CREATE TABLE IF NOT EXISTS posts (
      id INTEGER PRIMARY KEY,
      title TEXT NOT NULL,
      body TEXT NOT NULL
    );
  `);

  const { count } = db
    .prepare("SELECT COUNT(*) as count FROM posts")
    .get() as { count: number };

  if (count === 0) {
    const insert = db.prepare(
      "INSERT INTO posts (id, title, body) VALUES (@id, @title, @body)",
    );
    const insertMany = db.transaction((posts: Post[]) => {
      for (const post of posts) {
        insert.run(post);
      }
    });

    const posts: Post[] = Array.from({ length: TOTAL_POSTS }, (_, i) => {
      const n = i + 1;
      return {
        id: n,
        title: `Post #${n}`,
        body: `This is the body of post number ${n}. Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.`,
      };
    });

    insertMany(posts);
  }

  dbInstance = db;
  return dbInstance;
}

/**
 * Returns a page of posts with id strictly greater than `cursor`,
 * ordered by ascending id, along with whether more posts remain
 * after this page.
 */
export function getFeedPage(cursor: number): PageResult {
  const db = getDb();

  const rows = db
    .prepare(
      "SELECT id, title, body FROM posts WHERE id > ? ORDER BY id ASC LIMIT ?",
    )
    .all(cursor, PAGE_SIZE + 1) as Post[];

  const hasMore = rows.length > PAGE_SIZE;
  const posts = hasMore ? rows.slice(0, PAGE_SIZE) : rows;

  return { posts, hasMore };
}

import {
  $,
  component$,
  useSignal,
  useStore,
  useVisibleTask$,
} from "@builder.io/qwik";
import {
  routeLoader$,
  server$,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { getFeedPage, type Post } from "~/lib/db.server";

export const useFeedLoader = routeLoader$(() => {
  return getFeedPage(0);
});

export const loadMorePosts = server$(function (cursor: number) {
  return getFeedPage(cursor);
});

interface FeedState {
  posts: Post[];
  hasMore: boolean;
  loading: boolean;
}

export default component$(() => {
  const initial = useFeedLoader();

  const feed = useStore<FeedState>({
    posts: [...initial.value.posts],
    hasMore: initial.value.hasMore,
    loading: false,
  });

  const sentinelRef = useSignal<HTMLDivElement>();

  const appendPosts = $((incoming: Post[]) => {
    const existingIds = new Set(feed.posts.map((p) => p.id));
    for (const post of incoming) {
      if (!existingIds.has(post.id)) {
        feed.posts.push(post);
        existingIds.add(post.id);
      }
    }
  });

  // eslint-disable-next-line qwik/no-use-visible-task
  useVisibleTask$(({ cleanup }) => {
    const sentinelEl = sentinelRef.value;
    if (!sentinelEl) {
      return;
    }

    let disposed = false;

    const loadNextPage = async () => {
      if (feed.loading || !feed.hasMore || disposed) {
        return;
      }
      feed.loading = true;
      try {
        const lastPost = feed.posts[feed.posts.length - 1];
        const cursor = lastPost ? lastPost.id : 0;
        const result = await loadMorePosts(cursor);
        if (disposed) {
          return;
        }
        await appendPosts(result.posts);
        feed.hasMore = result.hasMore;
      } finally {
        feed.loading = false;
      }
      if (!feed.hasMore) {
        observer.disconnect();
      }
    };

    const observer = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (entry.isIntersecting) {
            void loadNextPage();
          }
        }
      },
      { root: null, rootMargin: "200px", threshold: 0 },
    );

    observer.observe(sentinelEl);

    cleanup(() => {
      disposed = true;
      observer.disconnect();
    });
  });

  return (
    <div class="feed-container">
      <h1>Feed</h1>
      <ul class="feed-list">
        {feed.posts.map((post) => (
          <li key={post.id} data-testid="feed-item" class="feed-item">
            <h2>{post.title}</h2>
            <p>{post.body}</p>
          </li>
        ))}
      </ul>

      {feed.loading && (
        <div data-testid="feed-loading" class="feed-loading">
          Loading more posts…
        </div>
      )}

      {!feed.hasMore && !feed.loading && (
        <div data-testid="feed-end" class="feed-end">
          End of feed
        </div>
      )}

      {feed.hasMore && (
        <div
          ref={sentinelRef}
          data-testid="feed-sentinel"
          class="feed-sentinel"
        />
      )}
    </div>
  );
});

export const head: DocumentHead = {
  title: "Feed",
  meta: [
    {
      name: "description",
      content: "Infinite scroll feed powered by Qwik City and SQLite",
    },
  ],
};

